// Parse the hub's SSE-framed JSON-RPC reply, then emit one item per task that has
// breached SLA: past its due date, not already done/cancelled, and not already high priority.
const raw = $input.first().json.data ?? $input.first().json.body ?? '';
const line = String(raw).split('\n').find((l) => l.startsWith('data:')) ?? '';
const rpc = JSON.parse(line.slice(5).trim());
if (rpc.result?.isError) throw new Error(rpc.result.content?.[0]?.text ?? 'tool error');
const tasks = JSON.parse(rpc.result?.content?.[0]?.text ?? '[]');
if (!Array.isArray(tasks)) return [];
const today = new Date().toISOString().slice(0, 10);
const done = new Set(['done', 'delivered', 'accepted', 'cancelled']);
const overdue = tasks.filter((t) => t.dueDate && String(t.dueDate).slice(0, 10) < today && !done.has(String(t.status)) && String(t.priority) !== 'high');
return overdue.map((t) => ({ json: { taskId: t.id } }));
